import{_ as i,o as a,c as e,ae as o}from"./chunks/framework.RRduUuAx.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/os/chapter-1.md","filePath":"szu/os/chapter-1.md"}'),r={name:"szu/os/chapter-1.md"};function t(d,l,h,c,u,n){return a(),e("div",null,[...l[0]||(l[0]=[o('<h2 id="第一节-什么是操作系统" tabindex="-1">第一节 什么是操作系统 <a class="header-anchor" href="#第一节-什么是操作系统" aria-label="Permalink to &quot;第一节 什么是操作系统&quot;">​</a></h2><ul><li>操作系统(Operating System, OS)是一种复杂的软件系统，是不同程序代码、数据结构、数据初始化文件的集合，可执行。</li><li>操作系统提供计算机用户与计算机硬件之间的接口，并管理计算机软件和硬件资源。</li></ul><ol><li>用户与硬件之间的接口</li><li>资源的管理者 <ul><li>1.处理机管理</li><li>2.内存管理</li><li>3.设备管理</li><li>4.文件管理</li></ul></li></ol><h3 id="背景知识" tabindex="-1">背景知识 <a class="header-anchor" href="#背景知识" aria-label="Permalink to &quot;背景知识&quot;">​</a></h3><ul><li><a href="https://lulaoshi.info/gpu/gpu-basic/computer-arch.html" target="_blank" rel="noreferrer">计算机体系结构</a></li></ul><h2 id="第二节-操作系统的发展" tabindex="-1">第二节 操作系统的发展 <a class="header-anchor" href="#第二节-操作系统的发展" aria-label="Permalink to &quot;第二节 操作系统的发展&quot;">​</a></h2><ol><li>无操作系统 <ul><li>第一代计算机（1945~1955 年）使用电子管作为主要的电子器件，用插件板上的硬连线或穿孔卡片表示程序，没有用来存储程序的内存，无操作系统。</li></ul></li><li>单道批处理系统 <ul><li>第二代计算机（1955~1965 年）使用晶体管作为主要的电子器件，开始使用磁性存储设备，内外存容量增加，计算机运算速度提高，出现了早期的单道批处理系统。</li></ul></li><li>多道程序系统 <ul><li>使用集成电路芯片作为主要的电子器件。多道程序系统的目的是为了提高 CPU 的利用率。</li><li>多道批处理系统 -&gt; 分时操作系统 -&gt; 多道程序系统</li></ul></li><li>微机操作系统</li><li>实时操作系统</li><li>批处理系统、分时系统、实时系统的特点 <ul><li>1.单道批处理系统：（1）自动性，（2）顺序性，（3）单道性</li><li>2.多道批处理系统：（1）多道性，（2）无序性，（3）调度性，（4）复杂性</li><li>3.分时系统：多路性、独立性、及时性和交互性。</li><li>4.实时系统：（1）多路性，（2）独立性，（3）及时性，（4）交互性，（5）可靠性</li></ul></li><li>操作系统产品现状 <ul><li>1.主机操作系统</li><li>2.服务器操作系统</li><li>3.微机操作系统</li><li>4.嵌入式操作系统</li></ul></li></ol><h2 id="第三节-操作系统的特征" tabindex="-1">第三节 操作系统的特征 <a class="header-anchor" href="#第三节-操作系统的特征" aria-label="Permalink to &quot;第三节 操作系统的特征&quot;">​</a></h2><ol><li>并发 <ul><li>并发是指两个或多个事件在<code>同一时间间隔</code>内发生。</li><li>并行是指多个事件同时发生。</li></ul></li><li>共享 <ul><li>共享是指系统中的资源可以供内存中多个并发执行的进程共同使用。</li><li>资源共享有两种方式，即互斥共享和同时共享。</li></ul></li><li>虚拟</li><li>异步性</li></ol><h2 id="第四节-操作系统的功能" tabindex="-1">第四节 操作系统的功能 <a class="header-anchor" href="#第四节-操作系统的功能" aria-label="Permalink to &quot;第四节 操作系统的功能&quot;">​</a></h2><ol><li>内存管理 <ul><li>1.内存分配</li><li>2.内存保护</li><li>3.地址映射</li><li>4.内存扩充</li></ul></li><li>进程管理</li><li>设备管理</li><li>文件管理</li></ol><h2 id="第五节-操作系统的体系结构" tabindex="-1">第五节 操作系统的体系结构 <a class="header-anchor" href="#第五节-操作系统的体系结构" aria-label="Permalink to &quot;第五节 操作系统的体系结构&quot;">​</a></h2><ol><li>软件体系结构简介 <ul><li>软件体系结构是一个复杂软件系统的高层结构，为软件系统提供了一个结构、行为和属性的高级抽象，包括系统元素的结构、元素间的相互关系、以及指导元素集成的模式和约束三个方面。</li><li>软件体系结构是一条贯穿软件系统整个生命周期的主线，是软件设计成功的基础和关键，也是对软件大型化、复杂化趋势的一种很好的应对决策。</li></ul></li><li>操作系统体系结构的分析 <ul><li>1.简单的监控程序模型</li><li>2.单体结构模型</li><li>3.层次结构模型</li><li>4.客户/服务器模型与微内核结构</li><li>5.动态可扩展结构模型</li></ul></li></ol><h2 id="第六节-指令的执行" tabindex="-1">第六节 指令的执行 <a class="header-anchor" href="#第六节-指令的执行" aria-label="Permalink to &quot;第六节 指令的执行&quot;">​</a></h2><ol><li>指令周期</li><li>取指令和执行指令</li><li>一个实例</li><li>指令的执行小结</li></ol><h2 id="思考与练习题" tabindex="-1">思考与练习题 <a class="header-anchor" href="#思考与练习题" aria-label="Permalink to &quot;思考与练习题&quot;">​</a></h2><h3 id="填空题" tabindex="-1">填空题 <a class="header-anchor" href="#填空题" aria-label="Permalink to &quot;填空题&quot;">​</a></h3><ol><li>单道批处理系统的内存中只能驻留<code></code>道用户作业，CPU 和内存资源被用户作业独占。</li><li>单道批处理系统与无操作系统的计算机系统相比而言，减少了<code></code>的时间。</li><li>操作系统是一组控制和管理计算机<code>软件</code>和<code>硬件</code>资源、合理地对各类作业进行调度，以及方便用户的程序集合。</li><li>并发是指两个或两个以上的事件在同一<code>时间间隔</code>内发生。</li><li>现代操作系统的特征包括<code>并发</code>、<code>共享</code>、<code>虚拟</code>、<code>异步</code>。</li></ol><h3 id="简答题" tabindex="-1">简答题 <a class="header-anchor" href="#简答题" aria-label="Permalink to &quot;简答题&quot;">​</a></h3><ol><li>请说明操作系统的作用和功能</li><li>请说明单道批处理系统、多道批处理系统、分时系统的特点及优缺点</li><li>内存管理有哪些主要功能？</li><li>请说明指令执行的过程。</li><li>操作系统具有哪些特征？</li></ol>',20)])])}const m=i(r,[["render",t]]);export{b as __pageData,m as default};
